function GameConfig:parseGameConfig(config)
    GameConfig.initPos = {}
    for i, pos in ipairs(config.initPos) do
        GameConfig.initPos[i] = VectorUtil.newVector3(pos.x, pos.y, pos.z)
    end

    GameConfig.SellAreaPos = VectorUtil.newVector3(config.SellAreaPos[1].x, config.SellAreaPos[1].y, config.SellAreaPos[1].z)
    GameConfig.AutoWorkoutPos = VectorUtil.newVector3(config.AutoWorkoutPos[1].x, config.AutoWorkoutPos[1].y, config.AutoWorkoutPos[1].z)
    GameConfig.muscleMass = tonumber(config.muscleMass) --初始肌肉量
    GameConfig.maxMuscleMass = tonumber(config.maxMuscleMass) --最大肌肉量
    GameConfig.muscleMassCoe = tonumber(config.muscleMassCoe) --肌肉量系数
    GameConfig.baseHealth = tonumber(config.baseHealth) --基础生命值
    GameConfig.lifeRecoveryCoe = tonumber(config.lifeRecoveryCoe) --生命恢复系数
    GameConfig.lifeRecoveryTime = tonumber(config.lifeRecoveryTime) --生命恢复间隔
    GameConfig.damageCoe = tonumber(config.damageCoe) --伤害系数
    GameConfig.baseDamage = tonumber(config.baseDamage) --基础伤害
    GameConfig.baseMoveSpeed = tonumber(config.baseMoveSpeed) --基础速度
    GameConfig.baseMoveSpeedModify = tonumber(config.baseMoveSpeedModify) --基础速度修正值
    GameConfig.muscleCaptureCoe = tonumber(config.muscleCaptureCoe) --肌肉夺取系数
    GameConfig.convertScale = tonumber(config.convertScale) --肌肉兑换金币比例
    GameConfig.respawnWaitTime = tonumber(config.respawnWaitTime) --复活等待时间
    GameConfig.invincibleTime = tonumber(config.invincibleTime) or 3 --复活无敌时间
    GameConfig.SafeAreaEffect = tostring(config.SafeAreaEffect) --安全区域特效
    GameConfig.teleportEffect = tonumber(config.teleportEffect) or 0 --#传送特效
    GameConfig.areaExpand = tonumber(config.areaExpand)
    GameConfig.AreaEventInterval = tonumber(config.AreaEventInterval) or 60 --地图事件间隔
    GameConfig.eventOpenNeedPlayerNum = tonumber(config.eventOpenNeedPlayerNum) or 1 --事件开启人数
    GameConfig.enemyRadius = tonumber(config.enemyRadius) or 1 --敌方半径
    GameConfig.bossRadius = tonumber(config.bossRadius) or 1 --boss半径
    GameConfig.actorDestroyEffect = tonumber(config.actorDestroyEffect) or 0 --GameActor销毁特效
    GameConfig.actorDestroyDelayTime = tonumber(config.actorDestroyDelayTime) or 0 --GameActor销毁延迟时间
    GameConfig.refreshActorTime = tonumber(config.refreshActorTime) or 5000
    GameConfig.currentChampionshipsLv = config.currentChampionshipsLv[1] or 0

    --组队相关
    TeamManager.CreateTeamLimit = tonumber(config.CreateTeamLimit) or 1000  --创建队伍的肌肉量限制
    TeamManager.WaitTimeJoinTeam = tonumber(config.WaitTimeJoinTeam) or 15 --加入队伍的等待时间
    TeamManager.JoinTeamMuscleLimit = tonumber(config.JoinTeamMuscleLimit) or 0.2 --加入队伍的肌肉量限制
    TeamManager.InitEffectRange = tonumber(config.InitEffectRange) or 5 --初始的光环半径大小
    TeamManager.MemberIncomeRatio = tonumber(config.MemberIncomeRatio) or 0.1 --队员肌肉量收益比例
    TeamManager.CaptainIncomeRatio = tonumber(config.CaptainIncomeRatio) or 0.1 --队长金币收益比例
end

return GameConfig